// تحليل نوع السيارة المختار
const { userId, vehicleType } = items[0].json;

// تصنيف أنواع السيارات
const vehicleCategories = {
  car: {
    category: 'personal',
    suggestedSellerType: 'private',
    marketDemand: 'high',
    recommendations: [
      'Focus on fuel efficiency specifications',
      'Highlight safety features and ratings',
      'Include maintenance history',
      'Add interior and exterior photos'
    ]
  },
  suv: {
    category: 'family',
    suggestedSellerType: 'private',
    marketDemand: 'very_high',
    recommendations: [
      'Emphasize space and seating capacity',
      'Highlight 4WD/AWD capabilities',
      'Include cargo space photos',
      'Mention family-friendly features'
    ]
  },
  truck: {
    category: 'commercial',
    suggestedSellerType: 'dealer',
    marketDemand: 'medium',
    recommendations: [
      'Focus on payload and towing capacity',
      'Include work history and usage',
      'Highlight durability and reliability',
      'Add photos of truck bed and equipment'
    ]
  },
  van: {
    category: 'commercial',
    suggestedSellerType: 'dealer',
    marketDemand: 'medium',
    recommendations: [
      'Emphasize cargo capacity',
      'Include commercial use history',
      'Highlight fuel efficiency',
      'Show interior cargo space'
    ]
  },
  motorcycle: {
    category: 'recreational',
    suggestedSellerType: 'private',
    marketDemand: 'seasonal',
    recommendations: [
      'Include performance specifications',
      'Highlight safety gear included',
      'Add maintenance records',
      'Show bike from multiple angles'
    ]
  },
  bus: {
    category: 'commercial',
    suggestedSellerType: 'company',
    marketDemand: 'low',
    recommendations: [
      'Focus on passenger capacity',
      'Include route history',
      'Highlight safety certifications',
      'Show interior and engine bay'
    ]
  }
};

// الحصول على معلومات النوع المختار
const vehicleInfo = vehicleCategories[vehicleType] || {
  category: 'other',
  suggestedSellerType: 'private',
  marketDemand: 'unknown',
  recommendations: ['Add detailed specifications']
};

// تحديد ما إذا كان تجاري أم لا
const isCommercial = ['truck', 'van', 'bus'].includes(vehicleType);

// اقتراحات السعر بناء على النوع
const pricingTips = {
  car: 'Check similar models in Sofia and Plovdiv',
  suv: 'SUVs have high resale value in Bulgaria',
  truck: 'Commercial vehicles: factor in business use',
  van: 'Delivery vans are in demand',
  motorcycle: 'Seasonal pricing - higher in spring/summer',
  bus: 'Specialized market - research thoroughly'
};

// إرجاع البيانات المعالجة
return [{
  json: {
    userId,
    vehicleType,
    vehicleInfo,
    isCommercial,
    pricingTip: pricingTips[vehicleType] || 'Research market prices',
    nextStep: 'seller_type_selection',
    processingTimestamp: new Date().toISOString(),
    bulgariaPeakSeason: vehicleType === 'motorcycle' ? 'April-September' : 'Year-round'
  }
}];
